import React, { useState } from 'react';
import './Login.css';

interface LoginProps {
  onLogin: (email: string, password: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password) {
      setError('Please fill in all fields');
      return;
    }

    if (!email.includes('@')) {
      setError('Please enter a valid email address');
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 1000));
      onLogin(email, password);
    } catch (err) {
      setError('Login failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-split-layout">
        {/* Left Side - Brand Section */}
        <div className="login-brand-section">
          <div className="brand-content">
            <h1 className="brand-title">GoFinance</h1>
            <p className="brand-subtitle">The most popular peer to peer lending at SEA</p>
            <button className="read-more-btn">Read More</button>
          </div>
          <div className="brand-decoration">
            <div className="circle-decoration"></div>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div className="login-form-section">
          <div className="login-form-container">
            <div className="login-header">
              <h2 className="login-title">Hello Again!</h2>
              <p className="login-subtitle">Welcome Back</p>
            </div>

            <form onSubmit={handleSubmit} className="login-form">
              {error && (
                <div className="error-message">
                  {error}
                </div>
              )}

              <div className="form-group">
                <div className="input-wrapper">
                  <img 
                    src="/Light-Icon/Iconly/Light-Outline/Message.svg" 
                    alt="Email" 
                    className="input-icon"
                  />
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Email Address"
                    className="form-input"
                    disabled={isLoading}
                  />
                </div>
              </div>

              <div className="form-group">
                <div className="input-wrapper">
                  <img 
                    src="/Light-Icon/Iconly/Light-Outline/Lock.svg" 
                    alt="Password" 
                    className="input-icon"
                  />
                  <input
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Password"
                    className="form-input"
                    disabled={isLoading}
                  />
                </div>
              </div>

              <button 
                type="submit" 
                className={`login-button ${isLoading ? 'loading' : ''}`}
                disabled={isLoading}
              >
                {isLoading ? (
                  <>
                    <div className="spinner"></div>
                    Signing in...
                  </>
                ) : (
                  'Login'
                )}
              </button>

              <div className="forgot-password">
                <a href="#" className="forgot-link">Forgot Password</a>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
